(() => {
  const artwork = {
    "bubble-feature": "data:image/webp;base64,",
    "merge-feature": "data:image/webp;base64,",
    "bone-feature": "data:image/webp;base64,",
    "bubble-play-1": "data:image/webp;base64,",
    "bubble-play-2": "data:image/webp;base64,",
    "merge-play-1": "data:image/webp;base64,",
    "merge-play-2": "data:image/webp;base64,",
    "bone-play-1": "data:image/webp;base64,",
    "bone-play-2": "data:image/webp;base64,"
  };

  document.documentElement.style.setProperty("--bubble-feature-art", `url("${artwork["bubble-feature"]}")`);
  document.documentElement.style.setProperty("--merge-feature-art", `url("${artwork["merge-feature"]}")`);

  document.querySelectorAll("img[data-art]").forEach((image) => {
    const source = artwork[image.dataset.art];
    if (source) image.src = source;
  });
})();
